#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long mn = LLONG_MAX, mx = LLONG_MIN;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(x < mn) mn = x;
            if(x > mx) mx = x;
        }
        long long ans = 2LL * (mx - mn);
        printf("%lld\n", ans);
    }
    return 0;
}

