    while(T--){
        int N; cin>>N;
        long long mn = LLONG_MAX, mx = LLONG_MIN;
        for(int i=0;i<N;i++){
            long long x; cin>>x;
            mn = min(mn, x);
            mx = max(mx, x);
        }
        long long ans = 2LL * (mx - mn);
        cout << ans << '\n';
    }
