import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        mn = 10**19
        mx = -10**19
        for _ in range(N):
            x = next(it)
            if x < mn:
                mn = x
            if x > mx:
                mx = x
        out.append(str(2 * (mx - mn)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

